using namespace std;
const int MAXN=100010;
int n,m,Max=0;
struct order
{
	char k[10];
	int a[50];
}o[MAXN];
int NOW[50],ans[50];
void init()
{
	cin>>n>>m;
	for (int i=1;i<=n;i++)
		{
		scanf("\n%s",o[i].k);
		int x;
		scanf("%d",&x);
		while (x)
			{
			o[i].a[++o[i].a[0]]=x&1;
			x>>=1;
			}
		if (o[i].a[0]==0)
			o[i].a[0]=1;
		Max=max(Max,o[i].a[0]);
		}
	Max=max(Max,((int)(log(m)/log(2))+1));
	int now=0;
	for (int i=Max;i>=1;i--)
		{
		for (int j=0;j<=1;j++)
			{
			int num=j;
			if (now+j*(1<<(i-1))>m)
				continue;
			for (int k=1;k<=n;k++)
				if (!strcmp(o[k].k,"OR")) num=(num|o[k].a[i]);
				else if (!strcmp(o[k].k,"XOR")) num=(num^o[k].a[i]);
				else num=(num&o[k].a[i]);
			if (num>ans[i])
				{ ans[i]=num; NOW[i]=j; }
			}
		now+=NOW[i]*(1<<(i-1));
		}
	int output=0;
	for (int i=1;i<=Max;i++)
		output+=(ans[i]*(1<<(i-1)));
	cout<<output<<endl;
	return ;
}
int main()
{
	init();
	return 0;
}

