#include <bits/stdc++.h>

typedef long long LL;
typedef long double db;
int R;
LL gcd(LL a, LL b) { return b ? gcd(b, a % b) : a; }
int calc(int n, LL a, LL b, LL c) {
	if (!n) return 0;
	LL g = std::abs(gcd(gcd(a, b), c));
	a /= g, b /= g, c /= g;
	if (c < 0) return calc(n, -a, -b, -c);
	db sq = sqrtl(R);
	LL d = (a * sq + b) / c;
	if (d) return calc(n, a, b - d * c, c) + n * (n + 1ll) / 2 * d;
	LL m = n * (a * sq + b) / c;
	LL tq = sq;
	LL res = n * m - calc(m, a * c, -b * c, a * a * R - b * b);
	if (tq * tq == R) res += m;
	return res;
}
int main() {
	std::ios_base::sync_with_stdio(false), std::cin.tie(0);
	int T; std::cin >> T;
	while (T --> 0) {
		int n;
		std::cin >> n >> R;
		int ans = n - 2 * calc(n, 1, 0, 1) + 4 * calc(n, 1, 0, 2);
		std::cout << ans << '\n';
	}
	return 0;
}

