template <class T, size_t L>
class block_allocator
{
private:
	union item
	{
		char t[sizeof(T)];
		item *next;
	};

	item *unused;
public:
	block_allocator()
		: unused(NULL) {}

	inline T *allocate()
	{
		if (!unused)
		{
			item *pool = new item[L], *tail = pool + L;
			for (item *p = pool; p != tail; p++)
				p->next = unused, unused = p;
		}

		T *tp = (T*)unused;
		unused = unused->next;
		new (tp) T();
		return tp;
	}
	inline void deallocate(T *tp)
	{
		item *p = (item*)tp;
		p->next = unused, unused = p;
	}
};

