	inline void set(int x, int d, int y) {
		a[x].ch[d] = y;
		if (y) a[y].fa = x;
	}

	inline bool isrt(int x) { // splay root
		int y = a[x].fa;
		return !y || (a[y].ch[0] != x && a[y].ch[1] != x); // not inclue ch[2]
	}

	int anc(int x) {
		while (!isrt(x)) x = a[x].fa;
		return x;
	}

	inline void pushup(int x) {
		if (a[x].kd == 0) {
			a[x].sum_dis = a[x].dis; a[x].cnt_cir = 0;
			rep (d, 0, 2) if (a[x].ch[d])
				a[x].sum_dis += a[a[x].ch[d]].sum_dis,
				a[x].cnt_cir += a[a[x].ch[d]].cnt_cir;
		}
		else {
			a[x].sum_dis = INF; a[x].cnt_cir = 1;
			rep (d, 0, 1) if (a[x].ch[d])
				Min(a[x].sum_dis, a[a[x].ch[d]].sum_dis),
				a[x].cnt_cir += a[a[x].ch[d]].cnt_cir;
		}
	}

	inline void torev(int x) {
		a[x].rev ^= 1;
		swap(a[x].ch[0], a[x].ch[1]);
		if (a[x].ch[2])
			swap(a[a[x].ch[2]].ch[0], a[a[x].ch[2]].ch[1]); // no rev tag
	}

	inline void pushdown(int x) {
		if (a[x].rev) {
			rep (d, 0, 1) if (a[x].ch[d]) // not inclue ch[2]
				torev(a[x].ch[d]);
			a[x].rev = 0;
		}
	}

	void clear(int x) {
		static int stack[maxN], Top;
		for (Top = 0; !isrt(x); x = a[x].fa) stack[++Top] = x;
		for (stack[++Top] = x; Top; --Top) pushdown(stack[Top]);
	}

	int find(int x, int dir) {
		for (pushdown(x); a[x].ch[dir]; pushdown(x = a[x].ch[dir]));
		//splay(x);
		return x;
	}

	inline void rot(int x) {
		int y = a[x].fa, z = a[y].fa, D = a[y].ch[1] == x, s = a[x].ch[!D];
		if (!isrt(y)) a[z].ch[a[z].ch[1] == y] = x;
		else if (a[z].ch[2] == y) a[z].ch[2] = x;
		a[y].ch[D] = s; a[x].ch[!D] = y;
		if (s) a[s].fa = y; a[y].fa = x, a[x].fa = z;
		pushup(y), pushup(x); //
	}

	void splay(int x, int &to = EMP) { // &, 否则for停不了 
		for (clear(x); !isrt(x) && x != to; rot(x)) {
			int y = a[x].fa;
			if (isrt(y) || y == to) continue;
			int z = a[y].fa;
			rot( ((a[z].ch[1] == y) == (a[y].ch[1] == x)) ? y : x );
		}
	}

	void pos_swap(int u, int c, int v) { // u -> ch[2] = c, u -> ch[1] = v
		rep (d, 0, 1) set(v, d, a[c].ch[d]);
		set(u, 1, c), set(u, 2, v); 
		pushup(v);
	}

	void access(int x) {
