			}
			else {
				int u = a[c].fa;
				splay(u); //
				int v = find(a[u].ch[1], 0);
				splay(v, a[u].ch[1]); 
				pos_swap(u, c, v);
				splay(x, a[u].ch[2]);
				pos_swap(u, x, c);
				a[x].ch[0] = 0, a[x].ch[1] = t, a[t].fa = x;
				pushup(x);
			}
		}
	}

	inline void ac(int x) {
		access(x);
		splay(x);
	}

	inline void chgrt(int x) {
		ac(x);
		torev(x);
	}

	inline void link(int x, int y) {
		chgrt(x); 
		a[x].fa = y;
		//ac(x);
	}

	inline void cut(int x, int y) {
		chgrt(x);
		ac(y);
		splay(x, a[y].ch[0]);
		if (!a[x].ch[1]) {
			a[x].fa = 0; a[y].ch[0] = 0;
