template<typename _Tp>
void retwist(Splay_Tree<_Tp> *o)
{
	o->parent->parent->splay();
	if (!o->parent->parent->is_root())
	{
		o->parent->parent->splay();
		if (o->parent->parent->dir() == 0)
			o->parent->parent->rotate();
		o->parent->parent->parent->ch[1] = o;
	}
	o->parent->pushdown_twist(), o->pushdown();
	Splay_Tree<_Tp> *p = o->parent->parent->parent;
	bool d = o->dir();
	o->parent->parent->sch(d, o->ch[!d])->sch(!d, o->parent->ch[!d])->pushup();
	o->parent->sch(d, o->ch[d])->sch(!d, o->parent->parent)->pushup_twist();
	o->ch[1] = Splay_Tree<_Tp>::Null, o->sch(0, o->parent)->pushup();
	o->parent = p;
	if (!o->is_root())
		o->rotate();
}

template<typename _Tp>
void access(Splay_Tree<_Tp> *o)
{
	if (o->splay()->parent->is_twist())
		retwist(o);
	o->ch[1] = Splay_Tree<_Tp>::Null, o->pushup();
	for (Splay_Tree<_Tp> *p = o->parent; p != Splay_Tree<_Tp>::Null; p->ch[1] = o, o->rotate(), p = o->parent)
		if (p->splay()->parent->is_twist())
			retwist(p);
}

template<typename _Tp>
