{
	access(o), o->reverse();
}

template<typename _Tp>
bool link(Splay_Tree<_Tp> *o1, Splay_Tree<_Tp> *o2, const _Tp &data)
{
	if (o1 == o2)
		return false;
	evert(o1), access(o2);
	if (o1->parent == Splay_Tree<_Tp>::Null)
	{
		Splay_Tree<_Tp> *e = new Splay_Tree<_Tp>(data);
		o1->sch(0, e)->pushup(), o2->sch(1, o1)->pushup();
		return true;
	}
	else if (!o2->cycle)
	{
		o2->ch[0] = Splay_Tree<_Tp>::Null, o2->ch[0] = o1->splay();
		Splay_Tree<_Tp> *e = new Splay_Tree<_Tp>(data);
		Splay_Tree<_Tp> *t = new Splay_Tree<_Tp>;
		t->cycle = true;
		t->sch(0, o1->ch[1])->sch(1, e)->pushup_twist(), o1->sch(1, t)->pushup(), o2->pushup();
		return true; 
	}
	else
		return false;
}

template<typename _Tp>
bool cut(Splay_Tree<_Tp> *o1, Splay_Tree<_Tp> *o2, const _Tp &data)
{
	if (o1 == o2)
		return false;
	evert(o1), access(o2);
	auto check = [&](const Splay_Tree<_Tp> *o) { return o->is_base() && o->data == data; };
	if (o1->parent == o2)
		if (!o1->ch[1]->is_twist())
			if (check(o1->ch[1]))
			{
				delete o1->ch[1];
				o2->ch[0] = o1->parent = o1->ch[1] = Splay_Tree<_Tp>::Null, o2->pushup();
				return true;
			}
			else
				return false;
		else
			if (o1->ch[1]->pushdown_twist(), check(o1->ch[1]->ch[0]) || check(o1->ch[1]->ch[1]))
			{
				o1->ch[1]->ch[1]->reverse();
				bool d = check(o1->ch[1]->ch[1]);
				Splay_Tree<_Tp> *t = o1->ch[1]->ch[!d];
				delete o1->ch[1]->ch[d], delete o1->ch[1];
				o1->sch(1, t)->pushup(), o2->pushup();
				return true;
			}
			else 
				return false;
	else
