      ans += dis[0][i];
      node_t *cur = new node_t;
      cur->succ = last;
      cur = merge(last,
                  merge(new node_t(last, dis[1][i] - dis[0][i]),
                        new node_t(last, dis[1][i])));
      last = cur;
    }
  }
  std::priority_queue<info_t> q;
  k--, printf("%lld\n", ans);
  q.push(info_t(last->val, last));
  for (; k-- && !q.empty();) {
    info_t cur = q.top();
