void upd(int id){
	if(c[id][id])return;
	for(int i=id+1;i<=T;i++)if(c[id][i]){
		if(!c[i][i]){
			swap(c[id],c[i]); swap(p[id],p[i]); return; 
		}else{
			c[id]^=c[i]; p[id]^=p[i];
		}
	}
}
void change(int x,bitset<N> y){
	b[x]^=y; vis[x]=1;
	for(int i=T;i;i--)if(p[i][x]){
		int t=0;
		for(int j=1;j<i;j++)if(p[j][x]){
			if(!c[j][j]){
				if(t){p[j]^=p[t]; } else t=j;
				continue;
			}
			p[j]^=p[i]; c[j]^=c[i];
		}
		if(t){p[t]^=p[i]; c[t]^=c[i];}
		c[i]^=y; 
		for(int j=1;j<i;j++)if(c[i][j]){
			if(c[j][j]){c[i]^=c[j]; p[i]^=p[j];}
			else{swap(c[j],c[i]); swap(p[j],p[i]); if(t)upd(t); return;}
		}
		upd(i);
		if(t)upd(t);
		return;
	}
}
void gauss(){
	for(int i=1;i<=T;i++)c[i]=b[i];
	for(int i=1;i<=T;i++){
		for(int j=i;j<=T;j++)if(c[j][i]){
