					x1=fa_e[x1]->y;
				end;
			end;
		end;
	end;
	
	inline void work(void (*f)(int, int, int))
	begin
		add_edge=f;
		int i;
		for i=1;i<=m;i++ do begin
			int u,v,len;
			read(u);read(v);read(len);
			addedge(u,v,len);
		end;
		dfs(1);
		for i=1;i<=n;i++ do begin
			for edge *te=first[i];te;te=te->next do begin
				if te->rev<te || te->f then continue;
				add_edge(i,te->y,te->len);
			end;
		end;
	end;
	
end;

