		for edge *te=first[x];te;te=te->next do begin
			int ty=te->y;
			if visit[ty] then continue;
			if !fa_e[ty] || fa_e[ty]->y!=x then continue;
			dfs3(ty,Nodes,Queries);
		end;
	end;
	
	#define SORT(x,cmp) (std::sort(&(x).front(),&(x).back()+1,(cmp)))
	
	int id_sum[MAXN];
	
	inline void pre_id_sum(std::vector<int> &A)
	begin
		int size=A.size();
		id_sum[A[0]]=A[0];
		int i;
		for i=1;i<size;i++ do begin
