			dfs3(ty,Nodes[id],Queries[id]);
			std::vector<int> &tmp_nodes=Nodes[id],&tmp_queries=Queries[id];
			if tmp_nodes.size() then begin
				SORT(tmp_nodes,cmp_dist);
				pre_id_sum(tmp_nodes);
			end;
			if tmp_queries.size() then begin
				SORT(tmp_queries,cmp_q_dist);
