			int qid=_qid[x];
			std::vector<int> tmp;
			tmp.push_back(qid);
			q_dist[qid]=_d[qid];
			for i=0;i<cnt;i++ do begin
				add_edges(tmp,Nodes[i]);
			end;
		end;
		for i=0;i<cnt;i++ do begin
			Nodes[i].clear();
			Queries[i].clear();
		end;
		for edge *te=first[x];te;te=te->next do begin
