	inline void merge(std::vector<int> &a,std::vector<int> &b,std::vector<int> &c,std::vector<int> &ret,bool (*cmp)(int,int))
	begin
		#undef begin
		#undef end
		std::vector<int> tmp(a.size()+b.size());
		std::merge(a.begin(),a.end(),b.begin(),b.end(),tmp.begin(),cmp);
		ret=std::vector<int>(tmp.size()+c.size());
		std::merge(tmp.begin(),tmp.end(),c.begin(),c.end(),ret.begin(),cmp);
		a.clear();b.clear();c.clear();tmp.clear();
		#define begin {
		#define end }
	end;
	
	inline void solve(int l,int r,std::vector<int> &all_nodes,std::vector<int> &all_queries)
	begin
		if l==r then begin
			all_nodes=dac_nodes[l];
			all_queries=dac_queries[l];
