		end;
		int sum=0;
		int i;
		for i=l;i<=r;i++ do begin
			sum+=dac_size[i];
		end;
		int tmp=0;
		for i=l;i<=r;i++ do begin
			if tmp*2<=sum && (tmp+dac_size[i])*2>=sum then break;
			tmp+=dac_size[i];
		end;
		int mid=i;
		std::vector<int> nL,nM,nR,qL,qM,qR;
		nM=dac_nodes[mid];
		qM=dac_queries[mid];
		
		if l<mid then begin
			solve(l,mid-1,nL,qL);
		end;
		if mid<r then begin
			solve(mid+1,r,nR,qR);
		end;
		
		bool fL=0;
		
		if qM.size() && nL.size() then begin
			if !fL then fL=1,pre_id_sum(nL);
			add_edges_dac(qM,nL,(dac_pos[mid]-dac_pos[1]),-(dac_pos[dac_n]-dac_pos[mid]));
