		if qR.size() && nL.size() then begin
			if !fL then fL=1,pre_id_sum(nL);
			add_edges_dac(qR,nL,(dac_pos[mid]-dac_pos[1]),-(dac_pos[dac_n]-dac_pos[mid]));
		end;
		if qR.size() && nM.size() then begin
			pre_id_sum(nM);
			add_edges_dac(qR,nM,(dac_pos[mid]-dac_pos[1]),-(dac_pos[dac_n]-dac_pos[mid]));
		end;
		
		merge(nL,nM,nR,all_nodes,cmp_dac_dist);
		merge(qL,qM,qR,all_queries,cmp_dac_q_dist);
	end;
	
	inline void solve_2(int l,int r,std::vector<int> &all_nodes,std::vector<int> &all_queries)
	begin
		if l==r then begin
			all_nodes=dac_nodes[l];
			all_queries=dac_queries[l];
			return;
		end;
		int sum=0;
		int i;
		for i=l;i<=r;i++ do begin
			sum+=dac_size[i];
		end;
		int tmp=0;
		for i=l;i<=r;i++ do begin
			if tmp*2<=sum && (tmp+dac_size[i])*2>=sum then break;
			tmp+=dac_size[i];
		end;
		int mid=i;
		std::vector<int> nL,nM,nR,qL,qM,qR;
		nM=dac_nodes[mid];
		qM=dac_queries[mid];
		
		if l<mid then begin
			solve_2(l,mid-1,nL,qL);
		end;
		if mid<r then begin
			solve_2(mid+1,r,nR,qR);
		end;
		
		bool fL=0;
		
		if qM.size() && nL.size() then begin
			if !fL then fL=1,pre_id_sum(nL);
			add_edges_dac(qM,nL);
		end;
		if qR.size() && nL.size() then begin
			if !fL then fL=1,pre_id_sum(nL);
			add_edges_dac(qR,nL);
		end;
		if qR.size() && nM.size() then begin
			pre_id_sum(nM);
			add_edges_dac(qR,nM);
		end;
		
		merge(nL,nM,nR,all_nodes,cmp_dac_dist);
		merge(qL,qM,qR,all_queries,cmp_dac_q_dist);
	end;
	
	inline void clear_dac()
	begin
		int i;
		for i=1;i<=dac_n;i++ do begin
			dac_nodes[i].clear();
			dac_queries[i].clear();
		end;
		dac_n=0;
	end;
	
	inline void set_dac_dist(std::vector<int> &Nodes,int d)
	begin
		int size=Nodes.size();
		int i;
		for i=0;i<size;i++ do begin
			int x=Nodes[i];
			dac_dist[x]=dist[x]+d;
