	inline int check_mindist(int x,int cyclen)
	begin
		return dep[x]<cyclen-dep[x];
	end;
	
	inline void solve_cycle(int x)
	begin
		
		
		int cyclen=cyc[x]->len;
		int last=cyc[x]->last;
		visit[x]=1;
		clear_visit();
		clear_cycle();
		int y=mo_e[x]->y;
		while y!=x do begin
			visit[y]=1;
			dep[y]-=dep[x];
			y=mo_e[y]->y;
		end;
		dep[x]=0;
		
		
		y=x;
		while 1 do begin
			bool f=false;
			for edge *te=first[y];te;te=te->next do if !visit[te->y] then begin
				f=true;
				int ty=te->y;
				fa_e[ty]=mo_e[ty]=NULL;
				cyc[ty]=NULL;
				SET_VISIT(ty);
				dep[ty]=te->len;
				dist[ty]=te->len;
				dfs1(ty,y);
				size[y]=size[ty]+1;
				now_root=ty;
				dfs3(ty,cycle_Nodes[y],cycle_Queries[y]);
				std::vector<int> &tmp_nodes=cycle_Nodes[y],&tmp_queries=cycle_Queries[y];
				if tmp_nodes.size() then begin
					SORT(tmp_nodes,cmp_dist);
				end;
				if tmp_queries.size() then begin
					SORT(tmp_queries,cmp_q_dist);
				end;
				if y<=n then begin
					int i;
					int size=tmp_queries.size();
					for i=0;i<size;i++ do begin
						Graph::addedge(n+tmp_queries[i],y);
					end;
					tmp_nodes.push_back(y);
					dist[y]=0;
				end else if _qid[y] then begin
					int qid=_qid[y];
					q_dist[qid]=_d[qid];
					int size=tmp_nodes.size();
					int i;
					for i=0;i<size;i++ do begin
						int x=tmp_nodes[i];
						if q_dist[qid]>=dist[x] then begin
							Graph::addedge(n+qid,x);
						end;
					end;
					tmp_queries.push_back(qid);
				end;
				if tmp_nodes.size() then begin
					SORT(tmp_nodes,cmp_dist);
				end;
				if tmp_queries.size() then begin
					SORT(tmp_queries,cmp_q_dist);
				end;
			end;
			if !f then begin
				if y<=n then begin
					cycle_Nodes[y].push_back(y);
					dist[y]=0;
				end else if _qid[y] then begin
					int qid=_qid[y];
					cycle_Queries[y].push_back(qid);
					q_dist[qid]=_d[qid];
				end;
				size[y]=1;
			end;
			y=mo_e[y]->y;
			if y==x then break;
		end;
		
		
		std::vector<int> tmp1,tmp2;
		
		int y1=mo_e[x]->y;
		
		if check_mindist(last,cyclen) then begin
			clear_dac();
			add_to_dac(x,0,dep[last],0);
			for y=mo_e[x]->y;y!=x;y=mo_e[y]->y do begin
				add_to_dac(y,dep[y],dep[last]-dep[y],-dep[y]);
			end;
			solve(1,dac_n,tmp1,tmp2);
			
			clear_dac();
			for y=last;y!=x;y=fa_e[y]->y do begin
				add_to_dac(y,dep[last]-dep[y],dep[y],-(dep[last]-dep[y]));
			end;
			add_to_dac(x,dep[last]-dep[x],dep[x],-(dep[last]-dep[x]));
			solve(1,dac_n,tmp1,tmp2);
		end else if !check_mindist(mo_e[x]->y,cyclen) then begin
			clear_dac();
			add_to_dac(x,0,cyclen-dep[y1],0);
			for y=last;y!=x;y=fa_e[y]->y do begin
				add_to_dac(y,cyclen-dep[y],dep[y]-dep[y1],-(cyclen-dep[y]));
			end;
			solve(1,dac_n,tmp1,tmp2);
			
			clear_dac();
			for y=y1;y!=x;y=mo_e[y]->y do begin
