				dis_sum[t[i].id]=dis_sum[cur]+t[i].dis;
				fa[t[i].id]=cur;
			}
	}
}
int find(int cur)
{
	if (anc[cur]<0) return cur;
	else return (anc[cur]=find(anc[cur]));
}
void calc_LCA(int cur)
{
	for (int i=list[cur]; i>-1; i=query[i].next)
	{
		int to=query[i].id;
		if (Link[to].u==cur) to=Link[to].v;
		else to=Link[to].u;
		if (vis[to]) Link[query[i].id].lca=anc_up[find(to)];
	}
}
void Union(int u, int v)
{
	u=find(u);  v=find(v);
	if (anc[u]<anc[v]) swap(u, v);
	anc[v]+=anc[u];
	anc[u]=v;
	if (deep[anc_up[u]]<deep[anc_up[v]]) anc_up[v]=anc_up[u];
}
void LCA()
{
	while (!dfs.empty()) dfs.pop();
	dfs.push(1);
	for (int i=1; i<=n; ++i) next[i]=h[i];
	for (int i=0; i<=n; ++i)
	{
		anc[i]=-1;
		anc_up[i]=0;
		vis[i]=false;
	}
	anc_up[1]=1;
	vis[1]=true;
	while (!dfs.empty())
	{
		int cur=dfs.top();
		bool flag=false;
		for (int i=next[cur]; i>-1; i=next[cur]=t[i].next)
			if (t[i].id!=fa[cur])
			{
				dfs.push(t[i].id);
				vis[t[i].id]=true;
				anc_up[t[i].id]=t[i].id;
				calc_LCA(t[i].id);
				flag=true;
				next[cur]=t[i].next;
				break;
			}
		if (flag) continue;
		Union(cur, fa[cur]);
		dfs.pop();
	}
}
void get_longest()
{
	if (Link[1].u==Link[1].v)
	{
		rev_sum=1;
		rev[1]=Link[1].u;
		return;
	}
	rev_sum=0;
	int cur=Link[1].u;
	while (cur!=Link[1].lca)
	{
		rev[++rev_sum]=cur;
		cur=fa[cur];
	}
	int tmp=rev_sum;
	cur=Link[1].v;
	while (cur!=Link[1].lca)
	{
		rev[++rev_sum]=cur;
		cur=fa[cur];
	}
	rev[++rev_sum]=cur;
	for (int i=1; i<=(rev_sum-tmp)/2; ++i)
		swap(rev[tmp+i], rev[rev_sum-i+1]);
}
void spread_num(int nid)
{
	int head=1, tail=1;
	q[1]=rev[nid];
	cross_num[rev[nid]]=nid;
	while (head<=tail)
	{
		int cur=q[head++];
		for (int i=h[cur]; i>-1; i=t[i].next)
			if (!vis[t[i].id])
			{
				vis[t[i].id]=true;
				cross_num[t[i].id]=nid;
				q[++tail]=t[i].id;
			}
	}
}
void block_of_each()
{
	for (int i=1; i<=n; ++i) vis[i]=false;
	for (int i=1; i<=rev_sum; ++i) vis[rev[i]]=true;
	for (int i=1; i<=rev_sum; ++i)
		spread_num(i);
	for (int i=1; i<=m; ++i)
		if (cross_num[Link[i].u]>cross_num[Link[i].v])
			swap(Link[i].u, Link[i].v);
}
int get_dis(int u, int v)
{
	if (fa[u]==v) swap(u, v);
	return dis_sum[v]-dis_sum[u];
}
void calc_ans()
{
	block[1].L=1; block[1].R=rev_sum;
	int i=2;
	while (cross_num[Link[i].u]!=cross_num[Link[i].v])
	{
		block[i].L=max(cross_num[Link[i].u], block[i-1].L);
		block[i].R=min(cross_num[Link[i].v], block[i-1].R);
		if (block[i].L>=block[i].R) break;
		++i;
	}
	i--;
	int maxnum=0;
	ans=int(1e9);
	for (int L=block[i].L, R=block[i].L; i>0; --i)
	{
		while (L!=block[i].L)
		{
			maxnum=max(maxnum, get_dis(rev[L], rev[L-1]));
			L--;
		}
		while (R!=block[i].R)
		{
			//printf("%d %d\n", R, block[i].R);
			maxnum=max(maxnum, get_dis(rev[R], rev[R+1]));
			R++;
		}
		ans=min(ans, max(Link[1].dis-maxnum, Link[i+1].dis));
	}
	printf("%d\n", ans);
}
void solve()
{
	identify_root();
	LCA();
	for (int i=1; i<=m; ++i)
		Link[i].dis=dis_sum[Link[i].u]+dis_sum[Link[i].v]-2*dis_sum[Link[i].lca];
	sort(Link+1, Link+1+m);
	get_longest();
	block_of_each();
	calc_ans();
}
int main()
{
	init();
	solve();
	return 0;
}

