#define Rep(x, a, b) for(int x=a; x<=b; x++)
typedef long long LL;
typedef pair<LL, LL> pll;
LL a, b, c, d;
vector<pll> ans;
map<LL, bool> t;
void save(LL a, LL b){
	if(!a || !b) return; 
	if(!t.count(a-b) && a!=b)
	{
		t[a-b]=1;
		ans.pb(mp(a, b));
	}
}
LL modul(LL a, LL b){
	if(a<b) swap(a, b);
	LL sh=a/b, hi, xi=1;
	for(hi=63; hi>=0; hi--) if(sh>>hi&1) break;
	save(a, b);
	while(!(xi>>hi&1) && ~hi)
	{
		save(a-xi*b, xi*b);
		save(a, a-2*xi*b); 
		xi<<=1;
	}
	while(sh)
	{
		if(sh&xi) save(a, b*xi), a-=b*xi, sh-=xi;
		xi>>=1;
	}
	return a;
}
LL GCD(LL a, LL b){
	return b?GCD(b, modul(a, b)):a;
}
LL gcd(LL a, LL b){ return b?gcd(b, a%b):a; }
