#include <stdio.h>
#include <iostream>
#include <algorithm>
using namespace std;

const int N = 10005;
typedef long double db;

char buf[1 << 20], *p1, *p2;
#define GC (p1 == p2 && (p2 = (p1 = buf) + fread(buf, 1, 1000000, stdin), p1 == p2) ? 0 : *p1 ++)
inline int _R() {
	int d = 0; char t; bool ty = 1;
	while (t = GC, (t < '0' || t > '9') && t != '-');
	t == '-' ? (ty = 0) : (d = t - '0');
	while (t = GC, t >= '0' && t <= '9') d = (d << 3) + (d << 1) + t - '0';
	return ty ? d : -d;
}

int n, tot, k, p;
int s[N], h[N], q[N], From[N][15];
db f[N][15], g[N];

db slope(db y1, db y2, db x1, db x2) {
	return (y1 - y2) / (x1 - x2);
}

Decimal gans(int i, int j) {
	if (j == 0) return h[1];
	return (s[i] - s[From[i][j]] + gans(From[i][j], j - 1)) / (i - From[i][j] + 1);
}
int main() {
	int i, j, x, st, lim, hd, tl, id;

	n = _R(), k = _R(), p = _R();
	h[1] = _R(), tot = 1;
	for (i = 2; i <= n; i ++) {
		x = _R();
		if (x > h[1]) h[++ tot] = x;
	}
	sort(h + 1, h + 1 + tot);			
	for (i = 1; i <= tot; i ++) {
		s[i] = s[i - 1] + h[i];
		f[i][0] = h[1];
	}

	k = min(k, n), lim = min(14, k);
	for (j = 1; j <= lim; j ++) {
		hd = tl = 1;
		q[tl] = 1, g[1] = s[1] - f[1][j - 1];
		for (i = 2; i <= tot; i ++) {
			while (hd < tl && slope(s[i], g[q[hd + 1]], i, q[hd + 1] - 1) >= slope(s[i], g[q[hd]], i, q[hd] - 1)) hd ++;
			f[i][j] = slope(s[i], g[q[hd]], i, q[hd] - 1);
			From[i][j] = q[hd];
			g[i] = s[i] - f[i][j - 1];
			while (hd < tl && slope(g[q[tl - 1]], g[q[tl]], q[tl - 1] - 1, q[tl] - 1) >= slope(g[q[tl]], g[i], q[tl] - 1, i - 1)) tl --;
			q[++ tl] = i;
		}
	}

	st = tot - k + lim;
	db maxx = 0;
	for (i = 0; i <= lim; i ++)
		if (f[st][i] > maxx) maxx = f[st][i], id = i;
	Decimal ans = gans(st, id);
	for (i = st + 1; i <= tot; i ++) ans = (ans + h[i]) / 2;
	cout << ans.to_string(p * 2) << endl;
}

