const int N = 10005;
typedef long double db;

char buf[1 << 20], *p1, *p2;
#define GC (p1 == p2 && (p2 = (p1 = buf) + fread(buf, 1, 1000000, stdin), p1 == p2) ? 0 : *p1 ++)
inline int _R() {
	int d = 0; char t; bool ty = 1;
	while (t = GC, (t < '0' || t > '9') && t != '-');
	t == '-' ? (ty = 0) : (d = t - '0');
	while (t = GC, t >= '0' && t <= '9') d = (d << 3) + (d << 1) + t - '0';
	return ty ? d : -d;
}

int n, tot, k, p;
int s[N], h[N], q[N], From[N][15];
db f[N][15], g[N];

db slope(db y1, db y2, db x1, db x2) {
	return (y1 - y2) / (x1 - x2);
}

Decimal gans(int i, int j) {
	if (j == 0) return h[1];
	return (s[i] - s[From[i][j]] + gans(From[i][j], j - 1)) / (i - From[i][j] + 1);
}
