	for (i = 2; i <= n; i ++) {
		x = _R();
		if (x > h[1]) h[++ tot] = x;
	}
	sort(h + 1, h + 1 + tot);			
	for (i = 1; i <= tot; i ++) {
		s[i] = s[i - 1] + h[i];
		f[i][0] = h[1];
	}

