		hd = tl = 1;
		q[tl] = 1, g[1] = s[1] - f[1][j - 1];
		for (i = 2; i <= tot; i ++) {
			while (hd < tl && slope(s[i], g[q[hd + 1]], i, q[hd + 1] - 1) >= slope(s[i], g[q[hd]], i, q[hd] - 1)) hd ++;
			f[i][j] = slope(s[i], g[q[hd]], i, q[hd] - 1);
			From[i][j] = q[hd];
			g[i] = s[i] - f[i][j - 1];
			while (hd < tl && slope(g[q[tl - 1]], g[q[tl]], q[tl - 1] - 1, q[tl] - 1) >= slope(g[q[tl]], g[i], q[tl] - 1, i - 1)) tl --;
			q[++ tl] = i;
		}
	}

	st = tot - k + lim;
	db maxx = 0;
	for (i = 0; i <= lim; i ++)
