  vector <int> cur;
  LL dis[N];

  inline int Min(int x, int y) {
    return dep[x] < dep[y] ? x : y;
  }

  inline void DFS(int x) {
    beg[x] = ++tim, h[0][tim] = x;
    for (int i = hed[x]; i; i = e[i].v) {
      if (!beg[e[i].p]) {
        par[e[i].p] = x;
        dep[e[i].p] = dep[x] + 1;
        dis[e[i].p] = dis[x] + e[i].w;
        DFS(e[i].p);
      }
    }
    end[x] = tim;
  }

  inline int LCA(int x, int y) {
    if (beg[x] > beg[y]) {
      swap(x, y);
    }
    if (end[x] >= end[y]) {
      return x;
    }
    int k = L[beg[y] - beg[x] + 1];
    assert(k < M);
    return par[Min(h[k][beg[x]], h[k][beg[y] - (1 << k) + 1])];
  }

  inline void Init() {
