    for(;x>='0'&&x<='9';x=getchar()) sum=sum*10+x-'0';
    return f*sum;
}

int n,head[M],e_size,du[M],stx,sty; bool f[M][M];
struct node { 
	double x,y;
	node operator -(const node &a) {return (node){x-a.x,y-a.y};}
	double operator *(const node &a) {return x*a.y-y*a.x;}
