} e[N << 1];

void inline add (int u, int v, int w, int o, int op) {
    e[++numE] = (Ed) { head[u], v, w, o, op };
    head[u] = numE;
}

int s[N], top;

vector<PII> pa;

bool ve[N << 1];

struct Node{
	int a, b, id, o;
	bool operator < (const Node &y) const {
		if (a != y.a) return a < y.a;
		return b < y.b;
	}
};

void euler(int u) {
	for (int &i = head[u]; i; ) {
		int v = e[i].v;
		if (ve[i]) {
			i = e[i].next;
			continue;
		}
		ve[i] = ve[i ^ 1] = 1;
		int op = e[i].op;
		PII t = mp(e[i].id, e[i].o);
		PII A = mp(e[i].id, 0);
		PII B = mp(e[i].o, 0);
		i = e[i].next;
		euler(v);
		if (op == 1) pa.pb(t);
		else pa.pb(B), pa.pb(A);
	}
}


vector<int> c, num;

bool vis[N];

int now;

int col[N];

int BZ;

void dfs1(int u) {
	col[u] = now;
	//cout << " dfs" << u << " " << cnt[u] << " " << d[u] << endl;
	if ((d[u] & 1) && u != BZ) c.pb(u);
	if (cnt[u] > 0) p = u;
	num.pb(u);
	vis[u] = 1;
	for (int i = head[u]; i; i = e[i].next) {
		int v = e[i].v;
		//cout << " chubian" << v << endl;
		if (!vis[v]) dfs1(v);
	}
}

void inline work(int p) {
	pa.clear();
